const PopularPage = () => {
    const [comics, setComics] = useState([]);
    const [genres, setGenres] = useState([]);
    const [loading, setLoading] = useState(true);
    const [selectedGenre, setSelectedGenre] = useState('');
    const [sortBy, setSortBy] = useState('views');
    const [showGenreDropdown, setShowGenreDropdown] = useState(false);

    useEffect(() => {
        fetchPopularComics();
    }, [selectedGenre, sortBy]);

    const fetchPopularComics = async () => {
        setLoading(true);
        try {
            let url = `http://localhost:5000/api/comics/popular?sort=${sortBy}`;
            if (selectedGenre) {
                url += `&genre=${encodeURIComponent(selectedGenre)}`;
            }
            const response = await fetch(url);
            const data = await response.json();
            setComics(data.comics || []);
            if (data.genres) setGenres(data.genres);
        } catch (error) {
            console.error('Error fetching popular comics:', error);
        } finally {
            setLoading(false);
        }
    };

    const sortOptions = [
        { value: 'views', label: 'Most Views', icon: <Eye size={14} /> },
        { value: 'rating', label: 'Highest Rated', icon: <Star size={14} /> },
        { value: 'newest', label: 'Newest First', icon: <TrendingUp size={14} /> },
    ];

    return (
        <div style={{ minHeight: '100vh', background: 'var(--bg-primary)' }}>
            <Navbar />

            {/* Page Header */}
            <div className="popular-page-header">
                <div className="popular-header-bg"></div>
                <div className="popular-header-overlay"></div>
                <div className="container popular-header-content">
                    <h1 className="popular-header-title">Popular Comics</h1>
                    <p className="popular-header-desc">
                        Discover the most read and trending comics loved by our community
                    </p>
                    <div className="popular-header-stats">
                        <span className="popular-stat-pill">
                            <TrendingUp size={14} />
                            {comics.length} Comics
                        </span>
                    </div>
                </div>
            </div>

            {/* Filter Bar */}
            <div className="container">
                <div className="popular-filter-bar glass-panel">
                    {/* Genre Filter */}
                    <div className="popular-filter-group">
                        <Filter size={16} style={{ color: 'var(--text-secondary)' }} />
                        <div className="popular-dropdown-wrapper">
                            <button
                                className="popular-dropdown-btn"
                                onClick={() => setShowGenreDropdown(!showGenreDropdown)}
                            >
                                <span>{selectedGenre || 'All Genres'}</span>
                                <ChevronDown size={14} />
                            </button>
                            {showGenreDropdown && (
                                <div className="popular-dropdown-menu">
                                    <button
                                        className={`popular-dropdown-item ${!selectedGenre ? 'active' : ''}`}
                                        onClick={() => { setSelectedGenre(''); setShowGenreDropdown(false); }}
                                    >
                                        All Genres
                                    </button>
                                    {genres.map(g => (
                                        <button
                                            key={g}
                                            className={`popular-dropdown-item ${selectedGenre === g ? 'active' : ''}`}
                                            onClick={() => { setSelectedGenre(g); setShowGenreDropdown(false); }}
                                        >
                                            {g}
                                        </button>
                                    ))}
                                </div>
                            )}
                        </div>
                    </div>

                    {/* Sort Buttons */}
                    <div className="popular-sort-group">
                        {sortOptions.map(opt => (
                            <button
                                key={opt.value}
                                className={`popular-sort-btn ${sortBy === opt.value ? 'active' : ''}`}
                                onClick={() => setSortBy(opt.value)}
                            >
                                {opt.icon}
                                <span>{opt.label}</span>
                            </button>
                        ))}
                    </div>
                </div>
            </div>

            {/* Comics Grid */}
            <div className="container" style={{ paddingBottom: '4rem' }}>
                {loading ? (
                    <div className="comic-grid" style={{ marginTop: '2rem' }}>
                        {Array.from({ length: 12 }).map((_, i) => (
                            <SkeletonCard key={i} />
                        ))}
                    </div>
                ) : comics.length > 0 ? (
                    <div className="comic-grid" style={{ marginTop: '2rem' }}>
                        {comics.map((comic, index) => (
                            <PopularComicCard
                                key={comic._id || comic.id}
                                comic={comic}
                                rank={index + 1}
                            />
                        ))}
                    </div>
                ) : (
                    <div className="popular-empty-state">
                        <Flame size={48} style={{ color: 'var(--text-secondary)', marginBottom: '1rem' }} />
                        <h3>No comics found</h3>
                        <p>Try adjusting your filters to discover more comics.</p>
                    </div>
                )}
            </div>

            <Footer />
        </div>
    );
};

export default PopularPage;

import React, { useEffect, useState } from 'react';
import { useSearchParams } from 'react-router-dom';
import Navbar from '../components/Layout/Navbar';
import Footer from '../components/Layout/Footer';
import ComicGrid from '../components/Home/ComicGrid';

const SearchPage = () => {
    const [searchParams] = useSearchParams();
    const query = searchParams.get('q');
    const [comics, setComics] = useState([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        if (query) {
            fetchSearchResults();
        } else {
            setComics([]);
            setLoading(false);
        }
    }, [query]);

    const fetchSearchResults = async () => {
        setLoading(true);
        try {
            const response = await fetch(`http://localhost:5000/api/comics?q=${encodeURIComponent(query)}`);
            const data = await response.json();
            setComics(data);
        } catch (error) {
            console.error('Error fetching search results:', error);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div style={{ minHeight: '100vh', background: 'var(--bg-primary)' }}>
            <Navbar />
            <div style={{ paddingTop: '80px', minHeight: '60vh' }}>
                <div className="container">
                    <h2 className="section-title" style={{ marginTop: '2rem' }}>
                        Search Results for "{query}"
                    </h2>
                    
                    {loading ? (
                        <div style={{ color: 'white', textAlign: 'center', padding: '2rem' }}>Searching...</div>
                    ) : comics.length > 0 ? (
                        <ComicGrid title="" comics={comics} />
                    ) : (
                        <div style={{ color: 'gray', textAlign: 'center', padding: '4rem' }}>
                            No comics found matching your search.
                        </div>
                    )}
                </div>
            </div>
            <Footer />
        </div>
    );
};

export default SearchPage;

import React, { useEffect, useState, useRef } from 'react';
import { useParams, Link } from 'react-router-dom';

const ChapterManager = () => {
    const { id } = useParams();
    const [chapters, setChapters] = useState([]);
    const [selectedChapters, setSelectedChapters] = useState(new Set());
    const [comicTitle, setComicTitle] = useState('');
    const [newChapter, setNewChapter] = useState({
        chapter_number: '',
        title: '',
    });
    const [files, setFiles] = useState([]);
    const [uploading, setUploading] = useState(false);

    // For uploading to existing chapters
    const fileInputRef = useRef(null);
    const targetChapterIdRef = useRef(null);

    const fetchData = async () => {
        try {
            const response = await fetch(`http://localhost:5000/api/comics/${id}`);
            const data = await response.json();
            setChapters(data.chapters || []);
            setComicTitle(data.title);
        } catch (error) {
            console.error('Error fetching data:', error);
        }
    };

    useEffect(() => {
        fetchData();
    }, [id]);

    const handleAddChapter = async (e) => {
        e.preventDefault();
        try {
            // 1. Get Comic ID (ensure MongoDB _id)
            const comicRes = await fetch(`http://localhost:5000/api/comics/${id}`);
            const comicData = await comicRes.json();

            const payload = {
                comic_id: comicData._id,
                chapter_number: Number(newChapter.chapter_number),
                title: newChapter.title || `Chapter ${newChapter.chapter_number}`,
                date: new Date().toISOString().split('T')[0]
            };

            // 2. Create Chapter
            const response = await fetch('http://localhost:5000/api/chapters', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(payload)
            });

            if (response.ok) {
                const createdChapter = await response.json();

                // 3. Upload Images if selected
                if (files.length > 0) {
                    setUploading(true);
                    await uploadImages(createdChapter._id, files);
                    setUploading(false);
                }

                setNewChapter({ chapter_number: '', title: '' });
                setFiles([]);
                // Reset file input value manually
                if (document.getElementById('new-chapter-files')) {
                    document.getElementById('new-chapter-files').value = '';
                }

                fetchData(); // Refresh list
            } else {
                alert('Failed to add chapter');
            }
        } catch (error) {
            console.error('Error adding chapter:', error);
            setUploading(false);
        }
    };

    const uploadImages = async (chapterId, fileList) => {
        try {
            const formData = new FormData();
            for (let i = 0; i < fileList.length; i++) {
                formData.append('pages', fileList[i]);
            }

            const res = await fetch(`http://localhost:5000/api/upload/chapter/${chapterId}`, {
                method: 'POST',
                body: formData
            });

            if (!res.ok) {
                const err = await res.json();
                alert(`Upload failed: ${err.message}`);
            }
        } catch (error) {
            console.error('Upload error:', error);
            alert('Upload error occurred');
        }
    };

    const handleDelete = async (chapterId) => {
        if (!confirm('Delete this chapter?')) return;
        try {
            const response = await fetch(`http://localhost:5000/api/chapters/${chapterId}`, {
                method: 'DELETE',
            });
            if (response.ok) {
                setChapters(chapters.filter(c => c._id !== chapterId));
                setSelectedChapters(prev => {
                    const next = new Set(prev);
                    next.delete(chapterId);
                    return next;
                });
            }
        } catch (error) {
            console.error('Error deleting chapter:', error);
        }
    };

    const handleBulkDelete = async () => {
        if (selectedChapters.size === 0) return;
        if (!confirm(`Delete ${selectedChapters.size} chapters?`)) return;

        try {
            const response = await fetch('http://localhost:5000/api/chapters/bulk-delete', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ chapterIds: Array.from(selectedChapters) })
            });

            if (response.ok) {
                setChapters(chapters.filter(c => !selectedChapters.has(c._id)));
                setSelectedChapters(new Set());
            } else {
                alert('Failed to delete chapters');
            }
        } catch (error) {
            console.error('Error deleting chapters:', error);
        }
    };

    // --- Upload for existing chapter ---
    const handleUploadClick = (chapterId) => {
        targetChapterIdRef.current = chapterId;
        if (fileInputRef.current) {
            fileInputRef.current.click();
        }
    };

    const handleExistingFileChange = async (e) => {
        const selected = e.target.files;
        if (selected && selected.length > 0 && targetChapterIdRef.current) {
            if (!confirm(`Upload ${selected.length} images to this chapter?`)) {
                fileInputRef.current.value = '';
                return;
            }

            setUploading(true);
            await uploadImages(targetChapterIdRef.current, selected);
            setUploading(false);

            fileInputRef.current.value = '';
            targetChapterIdRef.current = null;
            alert('Images uploaded successfully!');
        }
    };
    // -----------------------------------

    const toggleSelectAll = () => {
        if (selectedChapters.size === chapters.length) {
            setSelectedChapters(new Set());
        } else {
            setSelectedChapters(new Set(chapters.map(c => c._id)));
        }
    };

    const toggleSelect = (chapterId) => {
        setSelectedChapters(prev => {
            const next = new Set(prev);
            if (next.has(chapterId)) {
                next.delete(chapterId);
            } else {
                next.add(chapterId);
            }
            return next;
        });
    };

    return (
        <div className="max-w-4xl mx-auto">
            {/* Hidden Input for Quick Upload */}
            <input
                type="file"
                multiple
                accept="image/*"
                ref={fileInputRef}
                className="hidden"
                onChange={handleExistingFileChange}
            />

            <div className="flex items-center gap-4 mb-6">
                <Link to="/admin/comics" className="text-gray-400 hover:text-white">
                    &larr; Back
                </Link>
                <div className="flex-1">
                    <h2 className="text-3xl font-bold text-white">Manage Chapters: <span className="text-purple-400">{comicTitle}</span></h2>
                </div>
                {selectedChapters.size > 0 && (
                    <button
                        onClick={handleBulkDelete}
                        className="bg-red-600 hover:bg-red-700 text-white font-bold py-2 px-4 rounded transition-colors"
                    >
                        Delete Selected ({selectedChapters.size})
                    </button>
                )}
            </div>

            {uploading && (
                <div className="mb-4 bg-blue-600/20 border border-blue-500 text-blue-200 px-4 py-3 rounded animate-pulse">
                    Please wait... Uploading images to Cloudflare R2...
                </div>
            )}

            <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                {/* Add Chapter Form */}
                <div className="bg-gray-800 p-6 rounded-xl shadow-lg border border-gray-700 h-fit">
                    <h3 className="text-xl font-bold text-white mb-4">Add New Chapter</h3>
                    <form onSubmit={handleAddChapter} className="space-y-4">
                        <div>
                            <label className="block text-gray-400 mb-1 text-sm">Chapter Number</label>
                            <input
                                type="number"
                                value={newChapter.chapter_number}
                                onChange={(e) => setNewChapter({ ...newChapter, chapter_number: e.target.value })}
                                className="w-full bg-gray-900 border border-gray-700 rounded p-2 text-white focus:border-purple-500 outline-none"
                                required
                            />
                        </div>
                        <div>
                            <label className="block text-gray-400 mb-1 text-sm">Title (Optional)</label>
                            <input
                                type="text"
                                value={newChapter.title}
                                onChange={(e) => setNewChapter({ ...newChapter, title: e.target.value })}
                                placeholder="e.g. The Beginning"
                                className="w-full bg-gray-900 border border-gray-700 rounded p-2 text-white focus:border-purple-500 outline-none"
                            />
                        </div>
                        <div>
                            <label className="block text-gray-400 mb-1 text-sm">Pages (Images)</label>
                            <input
                                id="new-chapter-files"
                                type="file"
                                multiple
                                accept="image/*"
                                onChange={(e) => setFiles(e.target.files)}
                                className="w-full bg-gray-900 border border-gray-700 rounded p-2 text-gray-300 text-sm focus:border-purple-500 outline-none file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-semibold file:bg-purple-600 file:text-white hover:file:bg-purple-700"
                            />
                            <p className="text-xs text-gray-500 mt-1">Select multiple images.</p>
                        </div>
                        <button
                            type="submit"
                            disabled={uploading}
                            className={`w-full font-bold py-2 rounded transition-colors ${uploading
                                    ? 'bg-gray-600 cursor-not-allowed text-gray-300'
                                    : 'bg-green-600 hover:bg-green-700 text-white'
                                }`}
                        >
                            {uploading ? 'Processing...' : 'Add Chapter'}
                        </button>
                    </form>
                </div>

                {/* Chapter List */}
                <div className="md:col-span-2 bg-gray-800 rounded-xl shadow-lg border border-gray-700 overflow-hidden">
                    <table className="w-full text-left">
                        <thead className="bg-gray-750 text-gray-400 border-b border-gray-700 uppercase text-xs">
                            <tr>
                                <th className="px-6 py-3">
                                    <input
                                        type="checkbox"
                                        checked={chapters.length > 0 && selectedChapters.size === chapters.length}
                                        onChange={toggleSelectAll}
                                        className="rounded border-gray-600 bg-gray-700 text-purple-600 focus:ring-purple-500"
                                    />
                                </th>
                                <th className="px-6 py-3">#</th>
                                <th className="px-6 py-3">Title</th>
                                <th className="px-6 py-3 text-right">Action</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-700 text-gray-300">
                            {chapters.map((chapter) => (
                                <tr key={chapter._id} className="hover:bg-gray-750">
                                    <td className="px-6 py-3">
                                        <input
                                            type="checkbox"
                                            checked={selectedChapters.has(chapter._id)}
                                            onChange={() => toggleSelect(chapter._id)}
                                            className="rounded border-gray-600 bg-gray-700 text-purple-600 focus:ring-purple-500"
                                        />
                                    </td>
                                    <td className="px-6 py-3 font-medium">{chapter.chapter_number}</td>
                                    <td className="px-6 py-3">{chapter.title}</td>
                                    <td className="px-6 py-3 text-right flex justify-end gap-2">
                                        <button
                                            onClick={() => handleUploadClick(chapter._id)}
                                            className="text-blue-400 hover:text-blue-300 border border-blue-900 hover:bg-blue-900/40 rounded px-2 py-1 text-xs transition-colors"
                                        >
                                            Upload
                                        </button>
                                        <button
                                            onClick={() => handleDelete(chapter._id)}
                                            className="text-red-400 hover:text-red-300 border border-red-900 hover:bg-red-900/40 rounded px-2 py-1 text-xs transition-colors"
                                        >
                                            Delete
                                        </button>
                                    </td>
                                </tr>
                            ))}
                            {chapters.length === 0 && (
                                <tr>
                                    <td colSpan="4" className="px-6 py-8 text-center text-gray-500 italic">
                                        No chapters found.
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
};

export default ChapterManager;

import React, { useEffect, useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';

const ComicEditor = () => {
    const { id } = useParams();
    const navigate = useNavigate();
    const isEditing = !!id;

    const [formData, setFormData] = useState({
        title: '',
        author: '',
        artist: '',
        status: 'Ongoing',
        cover_url: '',
        description: '',
        genres: '',
    });
    const [coverFile, setCoverFile] = useState(null);
    const [previewUrl, setPreviewUrl] = useState('');

    const fetchComic = async () => {
        try {
            const response = await fetch(`http://localhost:5000/api/comics/${id}`);
            const data = await response.json();
            setFormData({
                ...data,
                genres: Array.isArray(data.genres) ? data.genres.join(', ') : data.genres
            });
            // Display existing cover if available
            // If data.cover_url is a full R2 url (or resolved one), show it
            if (data.cover_url) {
                setPreviewUrl(data.cover_url);
            }
        } catch (error) {
            console.error('Error fetching comic:', error);
        }
    };

    useEffect(() => {
        if (isEditing) {
            fetchComic();
        }
    }, [id]);

    const handleChange = (e) => {
        setFormData({ ...formData, [e.target.name]: e.target.value });
    };

    const handleFileChange = (e) => {
        const file = e.target.files[0];
        if (file) {
            setCoverFile(file);
            // Create a temporary object URL for preview
            setPreviewUrl(URL.createObjectURL(file));
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        const payload = {
            ...formData,
            genres: formData.genres.split(',').map(g => g.trim()).filter(g => g)
        };

        try {
            // 1. Create or Update Comic first
            const url = isEditing
                ? `http://localhost:5000/api/comics/${id}`
                : 'http://localhost:5000/api/comics';
            const method = isEditing ? 'PUT' : 'POST';

            const response = await fetch(url, {
                method,
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(payload)
            });

            if (!response.ok) {
                alert('Failed to save comic data');
                return;
            }

            const comicData = await response.json();

            // 2. Upload cover image if selected
            if (coverFile) {
                // Determine comic ID to use for upload
                // If we edited, we have 'id' from params or comicData._id
                // If we created, comicData should contain the new comic's _id (or id)
                const comicIdToUpload = comicData._id || comicData.id;

                const uploadFormData = new FormData();
                uploadFormData.append('cover', coverFile);

                const uploadResponse = await fetch(`http://localhost:5000/api/upload/cover/${comicIdToUpload}`, {
                    method: 'POST',
                    body: uploadFormData
                });

                if (!uploadResponse.ok) {
                    const err = await uploadResponse.json();
                    alert('Comic saved, but image upload failed: ' + err.message);
                    // Still navigate back probably, or let user retry?
                    // For now, let's navigate back since the comic is saved
                }
            }

            navigate('/admin/comics');

        } catch (error) {
            console.error('Error saving comic:', error);
            alert('An error occurred');
        }
    };

    return (
        <div className="max-w-2xl mx-auto">
            <h2 className="text-3xl font-bold mb-6 text-white">{isEditing ? 'Edit Comic' : 'New Comic'}</h2>

            <form onSubmit={handleSubmit} className="bg-gray-800 p-8 rounded-xl shadow-lg border border-gray-700 space-y-6">

                {/* Title */}
                <div>
                    <label className="block text-gray-400 mb-2 font-medium">Title</label>
                    <input
                        type="text"
                        name="title"
                        value={formData.title}
                        onChange={handleChange}
                        className="w-full bg-gray-900 border border-gray-700 rounded-lg px-4 py-3 text-white focus:outline-none focus:border-purple-500 transition-colors"
                        required
                    />
                </div>

                {/* Author & Artist */}
                <div className="grid grid-cols-2 gap-6">
                    <div>
                        <label className="block text-gray-400 mb-2 font-medium">Author</label>
                        <input
                            type="text"
                            name="author"
                            value={formData.author}
                            onChange={handleChange}
                            className="w-full bg-gray-900 border border-gray-700 rounded-lg px-4 py-3 text-white focus:outline-none focus:border-purple-500 transition-colors"
                        />
                    </div>
                    <div>
                        <label className="block text-gray-400 mb-2 font-medium">Artist</label>
                        <input
                            type="text"
                            name="artist"
                            value={formData.artist}
                            onChange={handleChange}
                            className="w-full bg-gray-900 border border-gray-700 rounded-lg px-4 py-3 text-white focus:outline-none focus:border-purple-500 transition-colors"
                        />
                    </div>
                </div>

                {/* Status & Genres */}
                <div className="grid grid-cols-2 gap-6">
                    <div>
                        <label className="block text-gray-400 mb-2 font-medium">Status</label>
                        <select
                            name="status"
                            value={formData.status}
                            onChange={handleChange}
                            className="w-full bg-gray-900 border border-gray-700 rounded-lg px-4 py-3 text-white focus:outline-none focus:border-purple-500 transition-colors"
                        >
                            <option value="Ongoing">Ongoing</option>
                            <option value="Completed">Completed</option>
                            <option value="Hiatus">Hiatus</option>
                        </select>
                    </div>
                    <div>
                        <label className="block text-gray-400 mb-2 font-medium">Genres (comma separated)</label>
                        <input
                            type="text"
                            name="genres"
                            value={formData.genres}
                            onChange={handleChange}
                            className="w-full bg-gray-900 border border-gray-700 rounded-lg px-4 py-3 text-white focus:outline-none focus:border-purple-500 transition-colors"
                            placeholder="Action, Fantasy..."
                        />
                    </div>
                </div>

                {/* Cover Image Upload */}
                <div>
                    <label className="block text-gray-400 mb-2 font-medium">Cover Image</label>
                    <div className="flex flex-col space-y-3">
                        {/* Preview */}
                        {previewUrl && (
                            <div className="w-full h-64 bg-gray-900 rounded-lg overflow-hidden border border-gray-700 flex items-center justify-center">
                                <img src={previewUrl} alt="Cover Preview" className="h-full object-contain" />
                            </div>
                        )}

                        <input
                            type="file"
                            accept="image/*"
                            onChange={handleFileChange}
                            className="w-full bg-gray-900 border border-gray-700 rounded-lg px-4 py-3 text-white focus:outline-none focus:border-purple-500 transition-colors"
                        />
                        <p className="text-gray-500 text-sm">Upload an image to replace the current cover.</p>
                    </div>
                </div>

                {/* Legacy Cover URL (Optional fallback) */}
                <div>
                    <label className="block text-gray-400 mb-2 font-medium">Cover URL (Or use upload above)</label>
                    <input
                        type="text"
                        name="cover_url"
                        value={formData.cover_url}
                        onChange={handleChange}
                        className="w-full bg-gray-900 border border-gray-700 rounded-lg px-4 py-3 text-white focus:outline-none focus:border-purple-500 transition-colors"
                        placeholder="http://..."
                    />
                </div>

                {/* Description */}
                <div>
                    <label className="block text-gray-400 mb-2 font-medium">Description</label>
                    <textarea
                        name="description"
                        value={formData.description}
                        onChange={handleChange}
                        className="w-full bg-gray-900 border border-gray-700 rounded-lg px-4 py-3 text-white focus:outline-none focus:border-purple-500 transition-colors h-32"
                    />
                </div>

                {/* Submit */}
                <div className="flex justify-end pt-4">
                    <button
                        type="submit"
                        className="bg-purple-600 hover:bg-purple-700 text-white font-bold py-3 px-8 rounded-lg shadow-lg transform active:scale-95 transition-all duration-200"
                    >
                        {isEditing ? 'Update Comic' : 'Create Comic'}
                    </button>
                </div>
            </form>
        </div>
    );
};

export default ComicEditor;
